 * See https://github.com/Kotlin/kotlinx.coroutines/issues/4035
 */
class TakeCompletionTest : TestBase() {

    /**
     * Regression test: flowOf(1).take(1).onCompletion { if (it == null) awaitCancellation() }.first()
     * should return 1 and not hang forever.
     *
     * The bug occurred because take() was using the downstream collector as the owner for its
     * AbortFlowException. When first() threw its own AbortFlowException (with the same downstream
     * collector as owner), take() would incorrectly swallow it, causing the flow to appear to
     * complete successfully, which triggered the onCompletion block with null cause and hung.
     */
    @Test
    fun testTakeWithOnCompletionAndFirst() = runTest {
        val result = flowOf(1)
            .take(1)
            .onCompletion { if (it == null) awaitCancellation() }
            .first()
        assertEquals(1, result)
    }

    /**
     * The same issue occurred with take(100) even when the flow only had a few elements.
     */
    @Test
    fun testTakeWithLargerCountOnCompletionAndFirst() = runTest {
        val result = flowOf(1, 2, 3)
            .take(100)
            .onCompletion { if (it == null) awaitCancellation() }
            .first()
        assertEquals(1, result)
    }

    /**
     * Adding an intermediate no-op operator like onEach{} used to "fix" the issue
     * because it created a unique collector. Verify this still works.
     */
    @Test
    fun testTakeWithIntermediateOperatorOnCompletionAndFirst() = runTest {
        val result = flowOf(1)
            .take(1)
            .onEach { } // no-op
            .onCompletion { if (it == null) awaitCancellation() }
            .first()
        assertEquals(1, result)
    }

    /**
     * Verify that onCompletion receives the cancellation exception (not null)
     * when first() cancels the flow.
     */
    @Test
    fun testOnCompletionReceivesCancellationFromFirst() = runTest {
        var completionCause: Throwable? = Throwable("not called")
        val result = flowOf(1)
            .take(1)
            .onCompletion { cause ->
                completionCause = cause
            }
            .first()
        assertEquals(1, result)
        // The completion cause should be a CancellationException (AbortFlowException)
        // because first() cancels the flow after receiving the first element
        assertNotNull(completionCause)
        assertTrue(completionCause is CancellationException)
    }

    /**
     * Same test without take() - this was already working before the fix.
     */
    @Test
    fun testOnCompletionReceivesCancellationFromFirstWithoutTake() = runTest {
        var completionCause: Throwable? = Throwable("not called")
        val result = flowOf(1)
            .onCompletion { cause ->
                completionCause = cause
            }
            .first()
        assertEquals(1, result)
        assertNotNull(completionCause)
        assertTrue(completionCause is CancellationException)
    }

    /**
     * Verify that take() still properly completes the flow when all elements are taken.
     */
    @Test
    fun testTakeCompletesNormallyWhenAllElementsTaken() = runTest {
        var completionCause: Throwable? = Throwable("not called")
        val result = flowOf(1, 2)
            .take(2)
            .onCompletion { cause ->
                completionCause = cause
            }
            .toList()
        assertEquals(listOf(1, 2), result)
        // When take() completes because it has taken all elements (and upstream also completes),
        // the completion cause should be null
        assertNull(completionCause)
    }

    /**
     * Verify firstOrNull works correctly with take() and onCompletion.
     */
    @Test
    fun testTakeWithOnCompletionAndFirstOrNull() = runTest {
        val result = flowOf(1)
            .take(1)
            .onCompletion { if (it == null) awaitCancellation() }
            .firstOrNull()
        assertEquals(1, result)
    }

    /**
     * Verify nested take() works with onCompletion and first().
     */
    @Test
    fun testNestedTakeWithOnCompletionAndFirst() = runTest {
        val result = flowOf(1, 2, 3)
            .take(2)
            .take(1)
            .onCompletion { if (it == null) awaitCancellation() }
            .first()
        assertEquals(1, result)
    }
